-- ============================================================

-- ============ TABLES ============

create table if not exists public.profiles (
  id            uuid primary key references auth.users(id) on delete cascade,
  email         text not null,
  name          text not null default '',
  role          text not null default 'employee',
  position      text default '',
  department    text default '',
  manager_id    uuid references public.profiles(id),
  tasting_access boolean default false,
  active        boolean default true,
  created_at    timestamptz default now()
);

create table if not exists public.time_entries (
  id            text primary key,
  user_id       uuid not null references public.profiles(id),
  clock_in      timestamptz not null,
  clock_out     timestamptz,
  note          text default '',
  edited        boolean default false,
  edited_by     uuid references public.profiles(id),
  created_at    timestamptz default now()
);

create table if not exists public.shifts (
  id            text primary key,
  user_id       uuid not null references public.profiles(id),
  date          date not null,
  start_time    text not null,
  end_time      text not null,
  position      text default '',
  notes         text default '',
  created_at    timestamptz default now()
);

create table if not exists public.announcements (
  id            text primary key,
  title         text not null,
  body          text not null,
  author_id     uuid references public.profiles(id),
  created_at    timestamptz not null default now(),
  pinned        boolean default false
);

create table if not exists public.time_off (
  id            text primary key,
  user_id       uuid not null references public.profiles(id),
  start_date    date not null,
  end_date      date not null,
  type          text not null,
  reason        text default '',
  status        text default 'pending',
  reviewed_by   uuid references public.profiles(id),
  reviewed_at   timestamptz,
  review_note   text default '',
  created_at    timestamptz default now()
);

create table if not exists public.tastings (
  id            text primary key,
  date          date not null,
  day           text default '',
  from_time     text default '',
  to_time       text default '',
  location      text default '',
  distributor   text default '',
  supplier      text default '',
  rep           text default '',
  products      jsonb default '[]'::jsonb,
  created_at    timestamptz default now()
);

create table if not exists public.timesheets (
  id            text primary key,
  user_id       uuid not null references public.profiles(id),
  week_start    date not null,
  entries       jsonb default '[]'::jsonb,
  status        text default 'draft',
  submitted_at  timestamptz,
  reviewed_by   uuid references public.profiles(id),
  reviewed_at   timestamptz,
  review_note   text default '',
  created_at    timestamptz default now()
);


-- ============ ROW LEVEL SECURITY ============
-- All authenticated users can read/write everything.
-- Role-based restrictions are enforced by the portal UI.

alter table public.profiles       enable row level security;
alter table public.time_entries   enable row level security;
alter table public.shifts         enable row level security;
alter table public.announcements  enable row level security;
alter table public.time_off       enable row level security;
alter table public.tastings       enable row level security;
alter table public.timesheets     enable row level security;

drop policy if exists "auth_all" on public.profiles;
drop policy if exists "auth_all" on public.time_entries;
drop policy if exists "auth_all" on public.shifts;
drop policy if exists "auth_all" on public.announcements;
drop policy if exists "auth_all" on public.time_off;
drop policy if exists "auth_all" on public.tastings;
drop policy if exists "auth_all" on public.timesheets;

create policy "auth_all" on public.profiles       for all using (auth.role() = 'authenticated');
create policy "auth_all" on public.time_entries   for all using (auth.role() = 'authenticated');
create policy "auth_all" on public.shifts         for all using (auth.role() = 'authenticated');
create policy "auth_all" on public.announcements  for all using (auth.role() = 'authenticated');
create policy "auth_all" on public.time_off       for all using (auth.role() = 'authenticated');
create policy "auth_all" on public.tastings       for all using (auth.role() = 'authenticated');
create policy "auth_all" on public.timesheets     for all using (auth.role() = 'authenticated');


-- ============ AUTO-CREATE PROFILE ON SIGNUP ============
create or replace function public.handle_new_user()
returns trigger as $$
begin
  if not exists (select 1 from public.profiles where id = new.id) then
    values (
      new.id,
      new.email,
      coalesce(new.raw_user_meta_data->>'name', split_part(new.email, '@', 1)),
      coalesce(new.raw_user_meta_data->>'role', 'employee'),
      true
    );
  end if;
  return new;
end;
$$ language plpgsql security definer;

drop trigger if exists on_auth_user_created on auth.users;
create trigger on_auth_user_created
  after insert on auth.users
  for each row execute procedure public.handle_new_user();


